    }

    public static boolean calculateSumOfSquares(String input) {
        int sum = 0;
        for (char c : input.toCharArray()) {
            if (Character.isDigit(c)) {
                int num = Character.getNumericValue(c);
                sum += num * num;
            } else {
                return false; // Return false if any character is not a digit
            }
        }
        return sum > 0; // Return true if the sum of squares is greater than 0
    }
}
