public class Main {
    public static void main(String[] args) {
        // Example usage
        System.out.println(calculateSum("123abc45-67")); // [123, 45, -67]
        System.out.println(calculateSum("abc")); // []
    }

    public static List<Integer> calculateSum(String input) {
        List<Integer> result = new ArrayList<>();
        StringBuilder currentNumber = new StringBuilder();

        for (char c : input.toCharArray()) {
            if (Character.isDigit(c) || (c == '-' && currentNumber.length() == 0)) { // Handle negative numbers
                currentNumber.append(c);
            } else {
                if (currentNumber.length() > 0) {
                    result.add(Integer.parseInt(currentNumber.toString())); // Convert to int and add to result
                    currentNumber.setLength(0); // Reset for the next number
                }
            }
        }

        if (currentNumber.length() > 0) { // Check if there's a number left at the end
            result.add(Integer.parseInt(currentNumber.toString()));
        }

        return result;
    }
}
